  ('public-health-specialist-moex-00266', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '臺灣目前垃圾處理方法主要是以焚化為主，焚化爐的設置會引起環境污染與破壞的疑慮，但 仍具有相當多優點，下列何項不是焚化處理的優點？', '["垃圾處理較不受天候影響", "垃圾減量效率高、降低病媒危害", "降低溫室氣體排放，邁向淨零", "兼具發電效應，提高經濟價值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
